import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Priority {
  P1 = 1, // Red - Urgent
  P2 = 2, // Orange - High
  P3 = 3, // Blue - Medium
  P4 = 4  // Grey - Low/None
}

export interface Task {
  id: string;
  content: string;
  description?: string;
  projectId: string;
  isCompleted: boolean;
  priority: Priority;
  dueDate?: string; // ISO Date string
  createdAt: string;
}

export interface Project {
  id: string;
  name: string;
  color: string; // Hex code or tailwind class reference
  isInbox?: boolean;
  isFavorite?: boolean;
}

export type ViewType = 'INBOX' | 'TODAY' | 'UPCOMING' | 'PROJECT';

export interface ViewState {
  type: ViewType;
  projectId?: string;
}

// Gemini Parsing Result
export interface ParsedTask {
  content: string;
  description?: string;
  priority?: Priority;
  dueDate?: string;
  projectName?: string; // To match existing projects
}

import { GoogleGenAI, Type } from "@google/genai";
import { Priority } from "../types";

const apiKey = process.env.API_KEY || '';
// Note: In a real app, handle missing API key gracefully. 
// For this demo, we assume it's injected.

const ai = new GoogleGenAI({ apiKey });

export const parseTaskWithGemini = async (
  input: string, 
  availableProjects: string[]
): Promise<{
  content: string;
  description?: string;
  priority: Priority;
  dueDate?: string;
  projectName?: string;
} | null> => {
  if (!input.trim()) return null;

  const now = new Date().toISOString();

  const prompt = `
    You are a smart task assistant. Extract task details from the following natural language input: "${input}".

    Current time: ${now}.
    Available Projects: ${availableProjects.join(', ')}.

    Rules:
    - Extract the core task as 'content'.
    - If there are details regarding time or context not in the title, put them in 'description'.
    - Parse priority: "p1" or "urgent" -> 1, "p2" -> 2, "p3" -> 3, else 4.
    - Parse relative dates (e.g., "tomorrow", "next friday") into ISO 8601 format (YYYY-MM-DD) for 'dueDate'.
    - If a project name is mentioned (prefixed with # or just by name if unique), match it to one of the available projects.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            content: { type: Type.STRING },
            description: { type: Type.STRING },
            priority: { type: Type.INTEGER }, // 1-4
            dueDate: { type: Type.STRING },
            projectName: { type: Type.STRING }
          },
          required: ["content", "priority"]
        }
      }
    });

    const text = response.text;
    if (!text) return null;

    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini parsing error:", error);
    // Fallback: return basic object
    return {
      content: input,
      priority: 4
    };
  }
};

export const suggestSubtasks = async (taskContent: string): Promise<string[]> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Break down the task "${taskContent}" into 3-5 distinct, actionable subtasks. Return only a JSON array of strings.`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                }
            }
        });
        const text = response.text;
        return text ? JSON.parse(text) : [];
    } catch (e) {
        console.error(e);
        return [];
    }
}

import React, { useState } from 'react';
import { 
  Inbox, 
  Calendar, 
  CalendarDays, 
  Hash, 
  Plus, 
  ChevronDown, 
  ChevronRight,
  Layout
} from 'lucide-react';
import { Project, ViewState } from '../types';

