import React, { useState, useRef, useEffect } from 'react';
import { Calendar, Flag, Hash, Send, Sparkles, X } from 'lucide-react';
import { Priority, Project, ParsedTask } from '../types';
import { parseTaskWithGemini } from '../services/geminiService';

interface AddTaskProps {
  projects: Project[];
  defaultProjectId: string;
  onAddTask: (task: { content: string; description?: string; priority: Priority; projectId: string; dueDate?: string }) => void;
  onCancel: () => void;
}

const AddTask: React.FC<AddTaskProps> = ({ projects, defaultProjectId, onAddTask, onCancel }) => {
  const [content, setContent] = useState('');
  const [description, setDescription] = useState('');
  const [priority, setPriority] = useState<Priority>(Priority.P4);
  const [projectId, setProjectId] = useState<string>(defaultProjectId);
  const [dueDate, setDueDate] = useState<string>('');

  const [isAiProcessing, setIsAiProcessing] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!content.trim()) return;

    onAddTask({
      content,
      description: description.trim() || undefined,
      priority,
      projectId,
      dueDate: dueDate || undefined
    });
    setContent('');
    setDescription('');
  };

  const handleAiParse = async () => {
    if (!content.trim()) return;
    setIsAiProcessing(true);

    // Combine content and description for context
    const fullText = `${content} ${description}`;
    const projectNames = projects.map(p => p.name);

    const parsed = await parseTaskWithGemini(fullText, projectNames);

    if (parsed) {
      setContent(parsed.content);
      if (parsed.description) setDescription(parsed.description);
      if (parsed.priority) setPriority(parsed.priority);
      if (parsed.dueDate) setDueDate(parsed.dueDate);

      if (parsed.projectName) {
        const matchedProject = projects.find(p => p.name.toLowerCase() === parsed.projectName?.toLowerCase());
        if (matchedProject) setProjectId(matchedProject.id);
      }
    }
    setIsAiProcessing(false);
  };

  const priorityColors = {
    [Priority.P1]: 'text-red-600',
    [Priority.P2]: 'text-orange-500',
    [Priority.P3]: 'text-blue-500',
    [Priority.P4]: 'text-gray-500',
  };

  return (
    <div className="border border-gray-200 rounded-lg p-3 bg-white shadow-sm mb-4">
      <form onSubmit={handleSubmit}>
        <div className="mb-2">
          <input
            ref={inputRef}
            type="text"
            placeholder="Task name"
            className="w-full text-sm font-medium text-gray-800 placeholder-gray-400 focus:outline-none mb-1.5"
            value={content}
            onChange={(e) => setContent(e.target.value)}
            disabled={isAiProcessing}
          />
          <textarea
            placeholder="Description"
            rows={1}
            className="w-full text-xs text-gray-600 placeholder-gray-400 focus:outline-none resize-none"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            disabled={isAiProcessing}
          />
        </div>

        <div className="flex items-center justify-between gap-2 mb-3">
          <div className="flex items-center gap-2">
            {/* Due Date Button - Simplified for Demo */}
            <button 
                type="button" 
                className={`flex items-center gap-1 px-2 py-1 rounded border border-gray-200 text-xs text-gray-500 hover:bg-gray-50 ${dueDate ? 'text-green-600 border-green-200 bg-green-50' : ''}`}
                onClick={() => {
                    // Simple toggle for demo purposes
                    const tomorrow = new Date();
                    tomorrow.setDate(tomorrow.getDate() + 1);
                    setDueDate(dueDate ? '' : tomorrow.toISOString().split('T')[0]);
                }}
            >
              <Calendar size={14} />
              {dueDate ? dueDate : 'Due date'}
            </button>

            {/* Priority Selector */}
            <div className="relative group">
                <button type="button" className={`flex items-center gap-1 px-2 py-1 rounded border border-gray-200 text-xs hover:bg-gray-50 ${priorityColors[priority]}`}>
                    <Flag size={14} fill={priority === Priority.P4 ? 'none' : 'currentColor'} />
                    {priority === Priority.P4 ? 'Priority' : `P${priority}`}
                </button>
                <div className="absolute top-full left-0 mt-1 w-24 bg-white border border-gray-200 rounded shadow-lg hidden group-hover:block z-10">
                    {[Priority.P1, Priority.P2, Priority.P3, Priority.P4].map(p => (
                        <div key={p} onClick={() => setPriority(p)} className="flex items-center gap-2 px-3 py-2 hover:bg-gray-100 cursor-pointer text-xs">
                             <Flag size={14} className={priorityColors[p]} fill={p === Priority.P4 ? 'none' : 'currentColor'}/> P{p}
                        </div>
                    ))}
                </div>
            </div>
          </div>
        </div>

        <div className="flex items-center justify-between border-t border-gray-100 pt-2">
            <div className="relative group">
                <button type="button" className="flex items-center gap-1.5 px-2 py-1.5 rounded hover:bg-gray-100 text-xs text-gray-600">
                    <Hash size={14} />
                    {projects.find(p => p.id === projectId)?.name || 'Project'}
                </button>
                 <div className="absolute top-full left-0 mt-1 w-40 max-h-40 overflow-y-auto bg-white border border-gray-200 rounded shadow-lg hidden group-hover:block z-10">
                    {projects.map(p => (
                        <div key={p.id} onClick={() => setProjectId(p.id)} className="px-3 py-2 hover:bg-gray-100 cursor-pointer text-xs truncate">
                            {p.name}
                        </div>
                    ))}
                </div>
            </div>

          <div className="flex items-center gap-2">
            <button
              type="button"
              onClick={onCancel}
              className="px-3 py-1.5 rounded text-xs font-semibold text-gray-700 hover:bg-gray-100 bg-gray-50"
            >
              Cancel
            </button>
            <button
               type="button"
               onClick={handleAiParse}
               disabled={!content.trim() || isAiProcessing}
               className="p-1.5 rounded text-gray-500 hover:text-purple-600 hover:bg-purple-50 transition-colors disabled:opacity-50"
               title="Use AI to parse details"
            >
                {isAiProcessing ? (
                     <div className="animate-spin h-4 w-4 border-2 border-purple-500 rounded-full border-t-transparent"></div>
                ) : (
                    <Sparkles size={16} />
                )}
            </button>
            <button
              type="submit"
              disabled={!content.trim() || isAiProcessing}
              className={`px-3 py-1.5 rounded text-xs font-semibold text-white transition-colors ${!content.trim() ? 'bg-red-300 cursor-not-allowed' : 'bg-red-600 hover:bg-red-700'}`}
            >
              Add task
            </button>
          </div>
        </div>
      </form>
    </div>
  );
};

export default AddTask;

import React, { useState } from 'react';
import { Check, Calendar, MoreHorizontal, MessageSquareText } from 'lucide-react';
import { Task, Priority } from '../types';
import { suggestSubtasks } from '../services/geminiService';

interface TaskItemProps {
  task: Task;
  onComplete: (id: string) => void;
  onUpdate: (task: Task) => void;
  onDelete: (id: string) => void;
}

const TaskItem: React.FC<TaskItemProps> = ({ task, onComplete, onUpdate, onDelete }) => {
  const [isHovered, setIsHovered] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);

  const priorityBorderColor = {
    [Priority.P1]: 'border-red-500 bg-red-50',
    [Priority.P2]: 'border-orange-500 bg-orange-50',
    [Priority.P3]: 'border-blue-500 bg-blue-50',
    [Priority.P4]: 'border-gray-300 hover:border-gray-400',
  };

  const handleSuggest = async () => {
    setIsSuggesting(true);
    const suggestions = await suggestSubtasks(task.content);
    if (suggestions.length > 0) {
        // In a real app, these would be real subtasks. 
        // Here we just append them to description to show functionality.
        const newDesc = (task.description ? task.description + '\n\n' : '') + "AI Suggestions:\n- " + suggestions.join('\n- ');
        onUpdate({ ...task, description: newDesc });
    }
    setIsSuggesting(false);
  };

  return (
    <div 
      className="group flex items-start gap-3 py-3 border-b border-gray-100 last:border-0 hover:bg-gray-50 -mx-2 px-2 rounded-md transition-colors cursor-pointer"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <button
        onClick={() => onComplete(task.id)}
        className={`mt-0.5 flex-shrink-0 w-5 h-5 rounded-full border flex items-center justify-center transition-colors ${priorityBorderColor[task.priority]} group/check`}
      >
        <Check size={12} className="opacity-0 group-hover/check:opacity-100 text-gray-600" />
      </button>

      <div className="flex-grow min-w-0">
        <div className="flex items-start justify-between">
            <div className="text-sm text-gray-800 leading-tight">
                {task.content}
            </div>
        </div>

        {task.description && (
          <div className="text-xs text-gray-500 mt-1 line-clamp-2 whitespace-pre-wrap">
            {task.description}
          </div>
        )}

        <div className="flex items-center gap-3 mt-1.5">
          {task.dueDate && (
            <div className="flex items-center gap-1 text-xs text-red-600">
              <Calendar size={12} />
              <span>{task.dueDate}</span>
            </div>
          )}
        </div>
      </div>

      <div className={`flex items-center gap-1 opacity-0 ${isHovered ? 'opacity-100' : ''} transition-opacity`}>
         <button 
            onClick={(e) => { e.stopPropagation(); handleSuggest(); }}
            className="p-1 text-gray-400 hover:text-purple-600 rounded"
            title="Get AI subtask suggestions"
            disabled={isSuggesting}
         >
             {isSuggesting ? (
                 <div className="w-4 h-4 border-2 border-purple-500 rounded-full border-t-transparent animate-spin"></div>
             ) : (
                <MessageSquareText size={16} />
             )}
         </button>
         <button 
            onClick={(e) => { e.stopPropagation(); onDelete(task.id); }}
            className="p-1 text-gray-400 hover:text-red-600 rounded"
            title="Delete task"
         >
             <MoreHorizontal size={16} />
         </button>
      </div>
    </div>
  );
};

export default TaskItem;

import React, { useState } from 'react';
