export default ProjectModal;

import React, { useState, useEffect, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Menu, Plus, SlidersHorizontal, User } from 'lucide-react';
import Sidebar from './components/Sidebar';
import AddTask from './components/AddTask';
import TaskItem from './components/TaskItem';
import ProjectModal from './components/ProjectModal';
import { Task, Project, ViewState, Priority } from './types';

// Initial Data
const INITIAL_PROJECTS: Project[] = [
  { id: 'inbox', name: 'Inbox', color: '#808080', isInbox: true },
  { id: 'personal', name: 'Personal', color: '#dc2626' },
  { id: 'work', name: 'Work', color: '#2563eb' },
];

const INITIAL_TASKS: Task[] = [
  {
    id: 't1',
    content: 'Welcome to ToDo AI',
    description: 'Try adding a task like "Buy milk tomorrow at 5pm #Personal"',
    projectId: 'inbox',
    isCompleted: false,
    priority: Priority.P1,
    createdAt: new Date().toISOString()
  }
];

const App: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>(() => {
    const saved = localStorage.getItem('todo_ai_tasks');
    return saved ? JSON.parse(saved) : INITIAL_TASKS;
  });

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('todo_ai_projects');
    return saved ? JSON.parse(saved) : INITIAL_PROJECTS;
  });

  const [viewState, setViewState] = useState<ViewState>({ type: 'INBOX' });
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isAddingTask, setIsAddingTask] = useState(false);
  const [isProjectModalOpen, setIsProjectModalOpen] = useState(false);

  // Persistence
  useEffect(() => {
    localStorage.setItem('todo_ai_tasks', JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem('todo_ai_projects', JSON.stringify(projects));
  }, [projects]);

  // Derived State
  const activeTasks = tasks.filter(t => !t.isCompleted);

  const filteredTasks = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];

    switch (viewState.type) {
      case 'INBOX':
        return activeTasks.filter(t => t.projectId === 'inbox');
      case 'TODAY':
        return activeTasks.filter(t => t.dueDate === today);
      case 'UPCOMING':
        return activeTasks.filter(t => t.dueDate && t.dueDate > today);
      case 'PROJECT':
        return activeTasks.filter(t => t.projectId === viewState.projectId);
      default:
        return activeTasks;
    }
  }, [tasks, viewState]);

  const viewTitle = useMemo(() => {
    switch (viewState.type) {
      case 'INBOX': return 'Inbox';
      case 'TODAY': return 'Today';
      case 'UPCOMING': return 'Upcoming';
      case 'PROJECT': 
        return projects.find(p => p.id === viewState.projectId)?.name || 'Project';
      default: return 'Tasks';
    }
  }, [viewState, projects]);

  // Handlers
  const handleAddTask = (newTaskData: { content: string; description?: string; priority: Priority; projectId: string; dueDate?: string }) => {
    const newTask: Task = {
      id: uuidv4(),
      createdAt: new Date().toISOString(),
      isCompleted: false,
      ...newTaskData
    };
    setTasks(prev => [...prev, newTask]);
    setIsAddingTask(false);
  };

  const handleCompleteTask = (id: string) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, isCompleted: true } : t));
  };

  const handleUpdateTask = (updatedTask: Task) => {
    setTasks(prev => prev.map(t => t.id === updatedTask.id ? updatedTask : t));
  };

  const handleDeleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
  };

  const handleAddProject = (name: string, color: string) => {
    const newProject: Project = {
      id: uuidv4(),
      name,
      color
    };
    setProjects(prev => [...prev, newProject]);
  };

  return (
    <div className="flex h-screen bg-white">
      {/* Mobile Overlay */}
      {isSidebarOpen && (
        <div 
