      )}

      {/* Sidebar */}
      <Sidebar 
        projects={projects}
        currentView={viewState}
        onViewChange={(view) => {
          setViewState(view);
          setIsSidebarOpen(false);
        }}
        onAddProject={() => setIsProjectModalOpen(true)}
        isMobileOpen={isSidebarOpen}
      />

      {/* Main Content */}
      <main className="flex-1 min-w-0 flex flex-col h-screen">
        {/* Header */}
        <header className="h-12 border-b border-gray-100 flex items-center justify-between px-4 bg-white shrink-0 sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="p-1 hover:bg-gray-100 rounded md:hidden"
            >
              <Menu size={20} className="text-gray-600" />
            </button>
            <button 
              onClick={() => setViewState({ type: 'INBOX' })} // Reset to home essentially
              className="md:hidden"
            >
                 <span className="font-bold text-red-600 tracking-tight">ToDo AI</span>
            </button>
          </div>

          <div className="flex items-center gap-4">
