            <div className="h-7 w-7 rounded-full bg-red-600 text-white flex items-center justify-center text-xs font-semibold">
               AI
            </div>
          </div>
        </header>

        {/* Task List Area */}
        <div className="flex-1 overflow-y-auto">
          <div className="max-w-3xl mx-auto px-4 py-8 md:px-8">
            <header className="mb-6">
              <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                {viewTitle}
                {viewState.type === 'PROJECT' && (
                    <span className="text-xs font-normal text-gray-400 border border-gray-200 px-2 py-0.5 rounded">
                        {projects.find(p => p.id === viewState.projectId)?.isInbox ? 'Default' : 'Project'}
