import React, { useState, useRef } from 'react';
import { Mic, Square, Loader2, SendHorizontal, Keyboard } from 'lucide-react';
import { blobToBase64, processVoiceEntry, processTextEntry } from '../services/geminiService';
import { ProcessedInput } from '../types';

interface VoiceCaptureProps {
  onProcessed: (result: ProcessedInput) => void;
}

const VoiceCapture: React.FC<VoiceCaptureProps> = ({ onProcessed }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showTextInput, setShowTextInput] = useState(false);
  const [textInput, setTextInput] = useState('');

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'audio/webm' });
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      mediaRecorder.onstop = async () => {
        setIsProcessing(true);
        const audioBlob = new Blob(chunksRef.current, { type: 'audio/webm' });

        // Stop all tracks to release mic
        stream.getTracks().forEach(track => track.stop());

        try {
          const base64 = await blobToBase64(audioBlob);
          const result = await processVoiceEntry(base64);
          if (result) {
            onProcessed(result);
          }
        } catch (err) {
          console.error("Processing failed", err);
          alert("Could not process audio. Please try again.");
        } finally {
          setIsProcessing(false);
        }
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Microphone access is required for voice capture.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const handleTextSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!textInput.trim()) return;

    setIsProcessing(true);
    try {
        const result = await processTextEntry(textInput);
        if (result) onProcessed(result);
        setTextInput('');
        setShowTextInput(false);
    } finally {
        setIsProcessing(false);
    }
  };

  return (
    <div className="fixed bottom-0 left-0 md:left-64 right-0 p-6 flex flex-col items-center justify-end z-20 pointer-events-none">
       {/* Text Input Overlay */}
       {showTextInput && (
           <div className="pointer-events-auto w-full max-w-2xl mb-4 bg-white rounded-2xl shadow-xl border border-slate-200 p-2 animate-in slide-in-from-bottom-5">
               <form onSubmit={handleTextSubmit} className="flex gap-2">
                   <input 
                      autoFocus
                      className="flex-1 px-4 py-3 bg-transparent outline-none text-slate-800 placeholder:text-slate-400"
                      placeholder="Type your thought..."
                      value={textInput}
                      onChange={e => setTextInput(e.target.value)}
                      disabled={isProcessing}
                   />
                   <button 
                      type="submit" 
                      disabled={isProcessing || !textInput.trim()}
                      className="p-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors disabled:opacity-50"
                   >
                       {isProcessing ? <Loader2 className="animate-spin" size={20}/> : <SendHorizontal size={20}/>}
                   </button>
               </form>
           </div>
       )}

      <div className="pointer-events-auto flex items-center gap-4">
        {/* Keyboard Toggle */}
        <button 
            onClick={() => setShowTextInput(!showTextInput)}
            className="bg-white text-slate-500 p-3 rounded-full shadow-lg border border-slate-100 hover:text-indigo-600 transition-colors"
        >
            <Keyboard size={20} />
        </button>

        {/* Main Mic Button */}
        <button
            onClick={isRecording ? stopRecording : startRecording}
            disabled={isProcessing}
            className={`
            relative flex items-center justify-center w-16 h-16 rounded-full shadow-xl transition-all duration-300
            ${isRecording 
                ? 'bg-rose-500 text-white recording-pulse' 
                : isProcessing 
                    ? 'bg-slate-100 text-slate-400' 
                    : 'bg-indigo-600 text-white hover:bg-indigo-700 hover:scale-105'
            }
            `}
        >
            {isProcessing ? (
                <Loader2 size={24} className="animate-spin" />
            ) : isRecording ? (
                <Square size={24} fill="currentColor" />
            ) : (
                <Mic size={28} />
            )}
        </button>
      </div>

      <div className="h-6 mt-4 text-xs font-medium text-slate-400 text-center transition-opacity duration-300">
        {isRecording ? "Listening... Tap to stop" : isProcessing ? "EchoFlow is thinking..." : showTextInput ? "" : "Tap to speak"}
      </div>
    </div>
  );
};

