        <div className="flex items-center gap-2 mb-2 text-xs font-semibold opacity-60 uppercase tracking-wider">
            {isHabit ? <Activity size={14} /> : <StickyNote size={14} />}
            <span>{isHabit ? 'Habit' : 'Reflection'}</span>
            {item.mood && <span>• {item.mood}</span>}
        </div>

        <div className="font-serif text-lg text-slate-800 leading-relaxed">
            {item.content}
        </div>

        {item.description && (
            <div className="mt-3 pt-3 border-t border-black/5 text-sm opacity-80">
                {item.description}
            </div>
        )}

        <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity">
            <button onClick={() => onDelete(item.id)} className="p-1.5 bg-white/50 rounded-lg hover:bg-white text-slate-500 hover:text-rose-600">
                <MoreHorizontal size={16} />
            </button>
        </div>
    </div>
  );
};

