import React, { useState, useEffect, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Menu } from 'lucide-react';
import Sidebar from './components/Sidebar';
import VoiceCapture from './components/VoiceCapture';
import FlowItem from './components/FlowItem';
import { FlowItem as FlowItemType, ViewState, ProcessedInput, Priority } from './types';

const INITIAL_ITEMS: FlowItemType[] = [
  {
    id: 'welcome-1',
    type: 'NOTE',
    content: 'Welcome to EchoFlow. Your mind is for having ideas, not holding them.',
    description: 'Tap the microphone below to start dumping your thoughts. I will organize them for you.',
    createdAt: new Date().toISOString(),
    mood: 'focused'
  },
  {
    id: 'welcome-2',
    type: 'TASK',
    content: 'Try saying "Remind me to call Mom tomorrow at 5pm"',
    priority: Priority.P3,
    createdAt: new Date().toISOString(),
    isCompleted: false
  }
];

const App: React.FC = () => {
  const [items, setItems] = useState<FlowItemType[]>(() => {
    const saved = localStorage.getItem('echoflow_items');
    return saved ? JSON.parse(saved) : INITIAL_ITEMS;
  });

  const [viewState, setViewState] = useState<ViewState>({ type: 'FLOW' });
  const [isMobileOpen, setIsMobileOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('echoflow_items', JSON.stringify(items));
  }, [items]);

  const handleProcessedInput = (result: ProcessedInput) => {
    const newItems: FlowItemType[] = result.items.map(item => ({
      id: uuidv4(),
      createdAt: new Date().toISOString(),
      type: item.type,
      content: item.content,
      description: item.description,
      priority: item.priority as Priority,
      dueDate: item.dueDate,
      mood: item.mood as any,
      tags: item.tags,
      isCompleted: false
    }));

    // Add new items to the TOP of the list (Chronological stack)
    setItems(prev => [...newItems, ...prev]);
  };

  const handleComplete = (id: string) => {
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, isCompleted: !item.isCompleted } : item
    ));
  };

  const handleDelete = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const filteredItems = useMemo(() => {
    switch (viewState.type) {
      case 'TASKS':
        return items.filter(i => i.type === 'TASK' && !i.isCompleted);
      case 'JOURNAL':
        return items.filter(i => i.type === 'NOTE' || i.type === 'HABIT');
      case 'FLOW':
      default:
        return items.filter(i => !i.isCompleted);
    }
  }, [items, viewState]);

  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good morning";
    if (hour < 18) return "Good afternoon";
    return "Good evening";
  };

  return (
    <div className="flex h-screen bg-slate-50 text-slate-900 overflow-hidden">
      <Sidebar 
        currentView={viewState}
        onViewChange={setViewState}
        isMobileOpen={isMobileOpen}
        onCloseMobile={() => setIsMobileOpen(false)}
      />

      <main className="flex-1 flex flex-col relative w-full h-full">
        {/* Minimal Header */}
        <header className="h-16 flex items-center justify-between px-6 md:px-8 bg-slate-50/80 backdrop-blur-sm z-10">
          <button 
            onClick={() => setIsMobileOpen(true)}
            className="md:hidden p-2 -ml-2 text-slate-600 hover:bg-slate-200 rounded-lg transition-colors"
          >
            <Menu size={20} />
          </button>
          <div className="text-sm font-medium text-slate-400 ml-auto font-serif italic">
            {new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
          </div>
        </header>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto pb-40 scrollbar-hide">
          <div className="max-w-2xl mx-auto px-6 md:px-8 pt-4">

            {/* Dynamic Title */}
            <div className="mb-10">
              <h1 className="font-serif text-3xl md:text-4xl text-slate-800 mb-2">
                {viewState.type === 'FLOW' ? getGreeting() : 
                 viewState.type === 'TASKS' ? 'Action Items' : 'Reflections'}
              </h1>
              <p className="text-slate-500">
                 {viewState.type === 'FLOW' ? 'Your mental inbox is ready.' : 
                  viewState.type === 'TASKS' ? `${filteredItems.length} pending tasks.` : 'Notes from your journey.'}
              </p>
            </div>

            {/* Empty State */}
            {filteredItems.length === 0 && (
                <div className="flex flex-col items-center justify-center py-20 opacity-40">
                    <div className="w-16 h-1 bg-slate-200 rounded-full mb-4"></div>
                    <p className="text-sm">Clear mind, calm water.</p>
                </div>
            )}

            {/* Feed */}
            <div className="space-y-1 animate-in fade-in slide-in-from-bottom-4 duration-500">
              {filteredItems.map(item => (
                <FlowItem 
                  key={item.id} 
                  item={item} 
                  onComplete={handleComplete}
                  onDelete={handleDelete}
                />
              ))}
            </div>
          </div>
        </div>

        {/* Voice Capture Overlay */}
        <VoiceCapture onProcessed={handleProcessedInput} />
      </main>
    </div>
  );
};

