import React, { useState, useEffect, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Menu } from 'lucide-react';
import Sidebar from './components/Sidebar';
import VoiceCapture from './components/VoiceCapture';
import FlowItem from './components/FlowItem';
import { FlowItem as FlowItemType, ViewState, ProcessedInput, Priority } from './types';

const INITIAL_ITEMS: FlowItemType[] = [
  {
    id: 'welcome-1',
    type: 'NOTE',
    content: 'Welcome to EchoFlow. Your mind is for having ideas, not holding them.',
    description: 'Tap the microphone below to start dumping your thoughts. I will organize them for you.',
    createdAt: new Date().toISOString(),
    mood: 'focused'
  },
  {
    id: 'welcome-2',
    type: 'TASK',
    content: 'Try saying "Remind me to call Mom tomorrow at 5pm"',
    priority: Priority.P3,
    createdAt: new Date().toISOString(),
    isCompleted: false
  }
];

const App: React.FC = () => {
  const [items, setItems] = useState<FlowItemType[]>(() => {
    const saved = localStorage.getItem('echoflow_items');
    return saved ? JSON.parse(saved) : INITIAL_ITEMS;
  });

  const [viewState, setViewState] = useState<ViewState>({ type: 'FLOW' });
  const [isMobileOpen, setIsMobileOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('echoflow_items', JSON.stringify(items));
  }, [items]);

  const handleProcessedInput = (result: ProcessedInput) => {
    const newItems: FlowItemType[] = result.items.map(item => ({
      id: uuidv4(),
      createdAt: new Date().toISOString(),
      type: item.type,
      content: item.content,
      description: item.description,
      priority: item.priority as Priority,
      dueDate: item.dueDate,
      mood: item.mood as any,
      tags: item.tags,
      streak: item.streak,
      isCompleted: false
    }));

    // Add new items to the TOP of the list (Chronological stack)
    setItems(prev => [...newItems, ...prev]);
  };

  const handleComplete = (id: string) => {
    setItems(prev => prev.map(item => 
